@import "tailwindcss";

@theme {
  --color-primary: #64a19d;
  --color-primary-dark: #50817e;
  --color-secondary: #7464a1;
  --color-accent: #1cabc4;
  --font-display: 'adumu', sans-serif;
  --font-body: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

@font-face {
  font-family: 'adumu';
  src: url('/fonts/adumu/adumu-webfont.woff2') format('woff2'),
       url('/fonts/adumu/adumu-webfont.woff') format('woff');
  font-weight: normal;
  font-style: normal;
}

/* Navbar transition */
.navbar-transparent {
  background-color: transparent;
  transition: background-color 0.3s ease;
}

.navbar-solid {
  background-color: rgba(0, 0, 0, 0.9);
  backdrop-filter: blur(8px);
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  transition: background-color 0.3s ease;
}

/* Headings use display font */
h1, h2, h3, h4 {
  font-family: 'adumu', sans-serif;
  text-transform: uppercase;
}

/* Primary button style */
.btn-primary {
  display: inline-block;
  padding: 0.5rem 1.5rem;
  background-color: var(--color-primary);
  color: white;
  font-family: 'adumu', sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  font-size: 0.875rem;
  border-radius: 2px;
  transition: background-color 0.2s;
  text-decoration: none;
}

.btn-primary:hover {
  background-color: var(--color-primary-dark);
}

/* Smooth scroll */
html {
  scroll-behavior: smooth;
}

body {
  background-color: black;
  color: white;
  font-family: var(--font-body);
}

@tailwind base;
@tailwind components;
@tailwind utilities;

@font-face {
  font-family: 'adumu';
  src: url('/fonts/adumu/adumu-webfont.woff2') format('woff2'),
       url('/fonts/adumu/adumu-webfont.woff') format('woff');
  font-weight: normal;
  font-style: normal;
}

/* Navbar transition */
.navbar-transparent {
  @apply bg-transparent;
  transition: background-color 0.3s ease;
}

.navbar-solid {
  @apply bg-black/90 shadow-lg;
  backdrop-filter: blur(8px);
  transition: background-color 0.3s ease;
}

/* Headings use display font */
h1, h2, h3, h4 {
  font-family: 'adumu', sans-serif;
  text-transform: uppercase;
}

/* Primary button style */
.btn-primary {
  @apply inline-block px-6 py-2 bg-primary text-white uppercase tracking-wider
         hover:bg-primary-dark transition-colors duration-200 rounded-sm text-sm;
  font-family: 'adumu', sans-serif;
}

/* Smooth scroll */
html {
  scroll-behavior: smooth;
}

body {
  @apply bg-black text-white;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/** @type {import('tailwindcss').Config} */
module.exports = {
  content: ['./src/**/*.{html,ts}'],
  theme: {
    extend: {
      colors: {
        primary: '#64a19d',
        'primary-dark': '#50817e',
        secondary: '#7464a1',
        accent: '#1cabc4',
      },
      fontFamily: {
        display: ['adumu', 'sans-serif'],
        body: ['-apple-system', 'BlinkMacSystemFont', 'Segoe UI', 'Roboto', 'sans-serif'],
      },
    },
  },
  plugins: [],
}
